        return true;

    if($this->isAllowManageByContext(abs($aContentInfo[$CNF['FIELD_ALLOW_VIEW_TO']])))
        return true;

    parent::__construct($aObject, $oTemplate);

    $this->_aJsCodes = array();

    $this->addMarkers(array(
        'js_object' => $this->_oModule->_oConfig->getJsObject('entry')
    ));
}

